def calc_ak_znachenie_klapana(p: dict):
# Описание: Генерация шума в клапане# Ячейка: O4
# Формула: =E10/E9
	return p["ak_produvka_atmosfernoe_davlenie_mpa_davlenie_posle_klapana_mpa"]/p["ak_produvka_davlenie_v_nachale_truby_mpa_davlenie_do_klapana_mpa"]

def calc_ak_rashod_sredy_g_kg_s(p: dict):
# Описание: # Ячейка: O5
# Формула: =Расчеты!O24
	return p["rashod_sredy_g_kg_s"]

def calc_ak_temperatura_sredy_k(p: dict):
# Описание: # Ячейка: O6
# Формула: =Расчеты!E12+273.15
	return p["temperatura_sredy_s"]+273.15

def calc_ak_kriticheskaya_skorost_m_s(p: dict):
# Описание: # Ячейка: O7
# Формула: =Расчеты!O28
	return p["kriticheskaya_skorost_skr_m_s"]

def calc_ak_davlenie_na_vhode_v_shg_abs_mpa(p: dict):
# Описание: # Ячейка: O8
# Формула: =Расчеты!E13
	return p["davlenie_na_vhode_v_shg_ri_abs_mpa"]

def calc_ak_gazovaya_postoyannaya_m2s2_k(p: dict):
# Описание: # Ячейка: O10
# Формула: =Расчеты!O29
	return p["gazovaya_postoyannaya_m2_s2_k"]

def calc_ak_koefficient_adiabaty(p: dict):
# Описание: # Ячейка: O11
# Формула: =Расчеты!O31
	return p["koeffcient_adiabaty"]

def calc_ak_kolichestvo_stupenej_drosselirovaniya(p: dict):
# Описание: # Ячейка: O12
# Формула: =Расчеты!E17
	return p["kolichestvo_stupenej_drosselirovaniya_sht"]

def calc_ak_skorost_sredy_mezhdu_plastinami_shg_m_s(p: dict):
# Описание: # Ячейка: O13
# Формула: =O780/O778
	return p["ak_obemnyj_rashod_m3_s"]/p["ak_svobodnaya_ploschad_m2"]

def calc_ak_privedennaya_skorost(p: dict):
# Описание: # Ячейка: O14
# Формула: =((O11+1)/(O11-1)*(1-O4^((O11-1)/O11)))^0.5
	return ((p["ak_koefficient_adiabaty"]+1)/(p["ak_koefficient_adiabaty"]-1)*(1-p["ak_znachenie_klapana"]**((p["ak_koefficient_adiabaty"]-1)/p["ak_koefficient_adiabaty"])))**0.5

def calc_ak_chislo_maha(p: dict):
# Описание: # Ячейка: O15
# Формула: =(2/(O11-1)*(O4^(-(O11-1)/O11-1)))^0.5
	return (2/(p["ak_koefficient_adiabaty"]-1)*(p["ak_znachenie_klapana"]**(-(p["ak_koefficient_adiabaty"]-1)/p["ak_koefficient_adiabaty"]-1)))**0.5

def calc_ak_funkciya_k_m(p: dict):
# Описание: Доля срабатываемого в клапане изоэнтропийного теплоперепада, переходящая в тепловую энергию# Ячейка: O16
# Формула: =IF(O15<=(0.8)^0.5,8*10^-5*O15^3,(IF(AND(O15>(0.8)^0.5,O15<=(20)^0.2),10^(-4)*O15^5,(IF(O15>20^0.2,2*10^(-3))))))
	return excel_if(p["ak_chislo_maha"]<=(0.8)**0.5,8*10**-5*p["ak_chislo_maha"]**3,(excel_if(excel_and(p["ak_chislo_maha"]>(0.8)**0.5,p["ak_chislo_maha"]<=(20)**0.2),10**(-4)*p["ak_chislo_maha"]**5,(excel_if(p["ak_chislo_maha"]>20**0.2,2*10**(-3))))))

def calc_ak_moschnost_shuma_wkl_vt(p: dict):
# Описание: # Ячейка: O17
# Формула: =0.5*(O16*O5*O7^2*O14^2)
	return 0.5*(p["ak_funkciya_k_m"]*p["ak_rashod_sredy_g_kg_s"]*p["ak_kriticheskaya_skorost_m_s"]**2*p["ak_privedennaya_skorost"]**2)

def calc_ak_uroven_zvukovoj_moschnosti_klapana_lw_db(p: dict):
# Описание: # Ячейка: O18
# Формула: =IF(E6="Продувка",E57,10*LOG10(O17/(10^(-12))))
	return excel_if(p["ak_izdavaemyj_shum"]=="Продувка",p["udelnyj_obem_m3_kg"],10*math.log10(p["ak_moschnost_shuma_wkl_vt"]/(10**(-12))))

